import React from "react";
import axios from "axios";

class Data extends React.Component {
  constructor(props) {
    super(props);
    this.ip = "";
    this.data = "";
    this.loggedIn = false;
    this.isLoading = false;
    this.lastLoginFailed = false;
  }

  getClockData() {
    if (this.ip !== "") {
      console.log("try");
      axios
        .get("http://" + this.state.ip, { timeout: 1000 })
        .then((result) => {
          this.data = result.data;
          this.isLoading = false;

          if (this.data.NAME === "WallClock") {
            this.loggedIn = true;
          }
        })
        .catch((error) => {
          this.isLoading = false;
          this.lastLoginFailed = true;
        });
    } else {
      this.isLoading = false;
      this.lastLoginFailed = true;
    }
    return true;
  }
}

export default Data;
